#include<iostream>
#include<set>
using namespace std;
set<int> f1,f0;
int vis=0;
int main(){
	int n;
	scanf("%d",&n);
	int f;
	for(int i= 1;i<=n;i++){
		scanf("%d",&f);
		if(f==0){
			f0.insert(i);
		}
		else{
			f1.insert(i);
		}
	}
	int last=-1;
	int last_idex;
	set<int>::iterator it1 = f1.begin();
	set<int>::iterator it0 = f0.begin();
	int temp=1;
	while(1){
		if(f0.empty() && !f1.empty()){
			//printf("\n");
			temp=*it1;
			printf("%d\n",*it1);
			f1.erase(temp);
			vis++;
			it1 = f1.begin();
			continue;
		}
		if(f1.empty() && !f0.empty()){
			//printf("\n");
			temp=*it0;
			printf("%d\n",*it0);
			f0.erase(temp);
			vis++;
			it0 = f0.begin();
			continue;
		}
		if(last==-1 && (*it1)>(*it0)){
			last_idex=*it0;
			printf("%d ",*it0);
			f0.erase(last_idex);
			vis++;
			it0 = f0.begin();
			last=0;
		}
		else if(last==-1 && (*it1)<(*it0)){
			last_idex=*it1;
			printf("%d ",*it1);
			f1.erase(last_idex);
			vis++;
			it1=f1.begin();
			last=1;
		}
		else if(last==1){
			it0=f0.upper_bound(last_idex);
			if(it0==f0.end()){
				printf("\n");
				last=-1;
				it0=f0.begin();
				it1=f1.begin();
			}
			else{
				last=0;
				last_idex=*it0;
				printf("%d ",last_idex);
				f0.erase(last_idex);
				it0=f0.begin();
				vis++;
				if(f0.empty() && f1.upper_bound(last_idex)==f1.end()) printf("\n");
			}
		}
		else if(last==0){
			it1=f1.upper_bound(last_idex);
			if(it1==f1.end()){
				printf("\n");
				last=-1;
				it1=f1.begin();
				it0=f0.begin();
			}
			else{
				last=1;
				last_idex=*it1;
				printf("%d ",last_idex);
				f1.erase(last_idex);
				it1=f1.begin();
				vis++;
				if(f1.empty() && f0.upper_bound(last_idex)==f0.end()) printf("\n");
			}
		}
		if(vis==n){
			break;
		}
	}
	return 0;
}
